/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;

    // 1. Calculate the sorted array S
    const S = [...nums].sort((a, b) => a - b);

    // Helper function to check if array A is a cyclic rotation of array B
    // Since we are checking if the target sorted block S' is a rotation of the original block B,
    // we check if S' is a rotation of B.
    const isRotation = (B, S_prime) => {
        const k = B.length;
        if (k !== S_prime.length) return false;
        if (k === 0) return true;

        // Check all k possible shifts j (where j is the starting index in B that matches S_prime[0])
        for (let j = 0; j < k; j++) {
            let match = true;
            for (let t = 0; t < k; t++) {
                // The element at index t in S_prime must match the element in B at index (j + t) % k
                if (S_prime[t] !== B[(j + t) % k]) {
                    match = false;
                    break;
                }
            }
            if (match) return true;
        }
        return false;
    };

    // 2. Find divisors of N
    const divisors = [];
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            divisors.push(k);
            if (k * k !== n) {
                divisors.push(n / k);
            }
        }
    }

    let sumOfSortableK = 0;

    // 3. Check sortability for each divisor k
    for (const k of divisors) {
        let isSortable = true;

        if (k === 1) {
            // If k=1, no rotation is possible. The array must already be sorted.
            for (let i = 0; i < n; i++) {
                if (nums[i] !== S[i]) {
                    isSortable = false;
                    break;
                }
            }
        } else {
            // Check every block
            const numBlocks = n / k;
            for (let i = 0; i < numBlocks; i++) {
                const start = i * k;

                // Extract the original block B_i
                const B_i = nums.slice(start, start + k);

                // Extract the target sorted block S'_i
                const S_prime_i = S.slice(start, start + k);

                // Check if S'_i is a cyclic rotation of B_i
                if (!isRotation(B_i, S_prime_i)) {
                    isSortable = false;
                    break;
                }
            }
        }

        if (isSortable) {
            sumOfSortableK += k;
        }
    }

    return sumOfSortableK;
}

