bool is_rotation(const std::vector<long long>& B, const std::vector<long long>& S_prime) {
    int k = B.size();
    if (k == 0) return true;
    if (k != S_prime.size()) return false;

    // Check k possible starting shifts j in B
    for (int j = 0; j < k; ++j) {
        bool match = true;
        // Check if S_prime matches the rotation starting at j
        for (int t = 0; t < k; ++t) {
            // S_prime[t] should match B[(j + t) % k]
            if (S_prime[t] != B[(j + t) % k]) {
                match = false;
                break;
            }
        }
        if (match) return true;
    }
    return false;
}

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;

    // 1. Calculate the sorted array S
    std::vector<long long> S = nums;
    std::sort(S.begin(), S.end());

    // 2. Find divisors of N
    std::vector<int> divisors;
    for (int k = 1; k * k <= n; ++k) {
        if (n % k == 0) {
            divisors.push_back(k);
            if (k * k != n) {
                divisors.push_back(n / k);
            }
        }
    }

    long long sumOfSortableK = 0;

    // 3. Check sortability for each divisor k
    for (int k : divisors) {
        bool isSortable = true;

        if (k == 1) {
            // If k=1, rotation only works if the array is already sorted.
            if (nums != S) {
                isSortable = false;
            }
        } else {
            // Check every block
            int numBlocks = n / k;
            for (int i = 0; i < numBlocks; ++i) {
                int start = i * k;

                // Extract the original block B_i (nums[start...start+k-1])
                std::vector<long long> B_i;
                B_i.reserve(k);
                for (int j = 0; j < k; ++j) {
                    B_i.push_back(nums[start + j]);
