/**
 * Checks if sequence P is a cyclic rotation of sequence B.
 * Assumes |P| == |B| = k.
 * Implements this check in O(k) time using sequence matching concepts.
 * Specifically, it checks if P is a subsequence of B concatenated with itself (B+B).
 */
bool isCyclicRotation(const vector<long long>& B, const vector<long long>& P) {
    int k = B.size();
    if (k == 0) return true;
    if (B.size() != P.size()) return false;

    // Construct B_double = B + B
    vector<long long> B_double = B;
    B_double.insert(B_double.end(), B.begin(), B.end());

    // We need to find P as a subsequence of length k in B_double (length 2k).
